import{c as e,Q as r,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Glossary","description":"Terms used across MuHaven docs.","frontmatter":{"title":"Glossary","description":"Terms used across MuHaven docs."},"headers":[],"relativePath":"reference/glossary.md","filePath":"reference/glossary.md","lastUpdated":1780245214000}'),n={name:"reference/glossary.md"};function d(a,t,i,c,l,p){return r(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>mhUSDC</strong></td><td>MuHavenStable — confidential USDC wrapper on Arbitrum. The settlement asset for every MuHaven flow. Tickers: <code>mhUSDC</code> everywhere user-facing. Internal storage fields may still say <code>pusdc</code> for backward compatibility.</td></tr><tr><td><strong>RWA</strong></td><td>Real-World Asset. Tokenized representations of off-chain assets (US Treasuries, gold, growth baskets, shipping receivables). MuHaven&#39;s RWA tokens are fhERC-20 with FHE-encrypted balances.</td></tr><tr><td><strong>fhERC-20</strong></td><td>Fhenix-encrypted ERC-20. Standard ERC-20 surface with <code>euint128</code> balances instead of <code>uint256</code>.</td></tr><tr><td><strong>FHE</strong></td><td>Fully Homomorphic Encryption. Computation on ciphertext without decrypting. Fhenix CoFHE is the implementation MuHaven uses.</td></tr><tr><td><strong>CoFHE</strong></td><td>Co-processor Fully Homomorphic Encryption. Fhenix&#39;s architecture where encrypted state lives on Arbitrum but heavy FHE compute runs on a sidecar coprocessor + threshold network.</td></tr><tr><td><strong>MuHaven wallet</strong></td><td>The passkey-bound EIP-4337 smart account every MuHaven user holds. Powered by a <a href="https://docs.zerodev.app/" target="_blank" rel="noreferrer">ZeroDev</a> kernel under the hood; supports passkey signing, session keys, and pluggable validators.</td></tr><tr><td><strong>Passkey</strong></td><td>A WebAuthn credential — biometric (Touch ID, Windows Hello) or hardware key (YubiKey). The master signer for every MuHaven wallet.</td></tr><tr><td><strong>Session key</strong></td><td>A short-lived ECDSA key with narrow scope (target allowlist, selector allowlist, value cap, validUntil). Signs day-to-day actions without re-prompting the passkey.</td></tr><tr><td><strong>Tiered autonomy</strong></td><td>MuHaven&#39;s five-state machine: Advisory / Confirm-per-action / Policy-bound / Scoped autonomy / Paused. Controls how much the agent can do without asking. The live autonomous tier is Scoped autonomy.</td></tr><tr><td><strong>Policy gate</strong></td><td>Deterministic non-LLM code between the LLM and the signing path. Validates every tool intent against your tier + on-chain policy primitives. The LLM proposes; the gate disposes.</td></tr><tr><td><strong>CaMeL</strong></td><td>&quot;Capability-aware Multi-LLM&quot; pattern. Planner/action split — the planning LLM never directly invokes signers; a deterministic action layer mediates.</td></tr><tr><td><strong>PromptArmor</strong></td><td>Backend preprocessing layer that strips known prompt-injection patterns before the LLM sees user input.</td></tr><tr><td><strong>Lethal trifecta</strong></td><td>Simon Willison&#39;s framing for the worst-case agentic threat: prompt-injection-prone LLM + tools that move value + access to credentials. MuHaven defends by splitting the credentials (broker pattern) and making the action layer deterministic (CaMeL).</td></tr><tr><td><strong>HavenBot</strong></td><td>MuHaven&#39;s in-dashboard agent. Streaming chat + per-action ConfirmModal. Lives at <code>muhaven.app/agent</code>.</td></tr><tr><td><strong>MCP</strong></td><td><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a>. Anthropic&#39;s open spec for connecting tools to LLM hosts (Claude Code / Desktop / Cursor). <code>@muhaven/mcp</code> is MuHaven&#39;s MCP server.</td></tr><tr><td><strong>MCPB</strong></td><td>MCP Bundle. The official npm package format for MCP servers — manifest.json declares env vars + binaries + endpoints + tool sensitivity flags.</td></tr><tr><td><strong><code>muhaven-broker</code></strong></td><td>The long-lived per-user daemon shipped with <code>@muhaven/mcp</code>. Holds JWT + session key in OS keychain. Speaks Unix socket / named pipe, never TCP.</td></tr><tr><td><strong>OpenClaw</strong></td><td>An open standard for agent skills. Skills bundle MCP servers + a manifest declaring permissions. MuHaven publishes <code>muhaven-rwa-skill</code> to <a href="https://clawhub.com" target="_blank" rel="noreferrer">ClawHub</a>.</td></tr><tr><td><strong>ClawHub</strong></td><td>The central registry for OpenClaw skills.</td></tr><tr><td><strong>Three-tier confirmation</strong></td><td>OpenClaw + Telegram&#39;s USD-amount-based classifier: ≤$200 inline / $200-$5K Mini-App OTP / &gt;$5K passkey deeplink. Hard-coded; users can&#39;t raise.</td></tr><tr><td><strong>Hosted Checkout</strong></td><td><code>muhaven.app/pay/...</code> — issuer-minted pay links for non-customer buyers. Fragment-key URL scheme, AES-256-GCM payload, Stripe-pattern webhooks.</td></tr><tr><td><strong>Fragment-key URL</strong></td><td>A URL where the encryption key is in the URL fragment (<code>#k=...</code>), which browsers never send in <code>Referer</code> headers. The server stores ciphertext useless without the key.</td></tr><tr><td><strong><code>MuHavenSubscription</code></strong></td><td>The smart contract that atomically wraps a mhUSDC → RWA-token purchase. Single tx; encrypted output handle.</td></tr><tr><td><strong><code>MuHavenEscrow</code></strong></td><td>Two-phase confidential escrow used for yield distributions. Per-investor escrow created on <code>startDistribution</code>; redeemed on <code>claim</code>.</td></tr><tr><td><strong><code>RiskParams.sol</code></strong></td><td>Smart contract storing per-user encrypted policy thresholds. Branchless <code>FHE.select</code> hot path keeps the policy check off the decrypt timing side-channel.</td></tr><tr><td><strong><code>InvestorRegistry</code></strong></td><td>Paginated registry of MuHavenToken holders. Drives the yield-distribution batching loop.</td></tr><tr><td><strong><code>YieldDistributor</code></strong></td><td>State machine that orchestrates a per-epoch yield distribution: <code>startDistribution → batchCreate → fundFrom</code>.</td></tr><tr><td><strong><code>YieldSnapshot</code></strong></td><td>The point-in-time snapshot of holder shares + yields used to compute proportional distribution amounts.</td></tr><tr><td><strong><code>DefaultProtection</code></strong></td><td>Opt-in protection pool covering loss-of-principal scenarios on participating RWA tokens.</td></tr><tr><td><strong><code>EncryptedGovernance</code></strong></td><td>FHE-encrypted ballot voting; tally async-decrypted at proposal close.</td></tr><tr><td><strong><code>KYCAttestationRegistry</code></strong></td><td>Cross-chain KYC attestation stub. Cleartext jurisdictionHash + attestation signer; encrypted attestation period.</td></tr><tr><td><strong>ERC-3643</strong></td><td>The securities token standard. MuHaven RWA tokens have an <code>ERC3643KYCAdapter</code> that gates transfers on whitelist membership.</td></tr><tr><td><strong>OnchainID</strong></td><td>The identity standard ERC-3643 uses. Wallets bind to OnchainID records that carry claims (KYC tier 1 / tier 2 accredited / jurisdiction).</td></tr><tr><td><strong>Permit</strong></td><td>A signed authorization (EIP-2612-style or cofhe-specific) that grants temporary read-access to a specific encrypted handle. MuHaven uses cofhe permits to decrypt your own balances client-side.</td></tr><tr><td><strong><code>decryptForView</code></strong></td><td>The CoFHE client primitive that decrypts an encrypted handle to a cleartext value in your browser, with a permit. Never decrypts server-side.</td></tr><tr><td><strong><code>decryptForTx</code></strong></td><td>The CoFHE primitive that decrypts a handle for on-chain consumption (e.g., breach-path settlement). Settles back to the chain via <code>publishDecryptResult</code>.</td></tr><tr><td><strong><code>agent_audit_events</code></strong></td><td>The append-only WORM-style audit table backing every state-mutating action across all four surfaces.</td></tr><tr><td><strong><code>agent_user_state</code></strong></td><td>The Drizzle table tracking each user&#39;s current tier + pause state.</td></tr><tr><td><strong><code>/pause</code></strong></td><td>The kill-switch. Uninstalls the session-key validator in ≤1 Arbitrum block. Global across all surfaces.</td></tr><tr><td><strong>Advisory tier</strong></td><td>Every action prompts your passkey via WebAuthn. The default tier for fresh investors.</td></tr><tr><td><strong>Confirm-per-action tier</strong></td><td>Session key signs without re-prompting passkey within the 1-hour TTL. ConfirmModal still opens for cleartext preview.</td></tr><tr><td><strong>Policy-bound tier</strong></td><td>Designed automation tier: a cron policy engine would sign within your encrypted thresholds without per-action confirmation, auto-pausing on breach. The auto-signing engine is built but disabled in every deployment — selecting it gives an allowlist-scoped tier without a live risk engine. Not the live autonomous tier.</td></tr><tr><td><strong>Scoped autonomy tier</strong></td><td>The live autonomous tier. A bounded session key plus a broker daemon sign without prompting within a per-trade cap and TTL. Opt-in; revocable via <code>/pause</code>.</td></tr><tr><td><strong>Paused tier</strong></td><td>All <code>propose</code> tools return 423. Read tools work. Resume requires master passkey.</td></tr></tbody></table>',2)])])}const u=e(n,[["render",d]]);export{g as __pageData,u as default};
